module.render:
const color = args.color || '#f5a623';
const empty = (args.emptycolor && String(args.emptycolor).trim()) || '';
const symbols = { star: '★', heart: '♥', circle: '●', square: '■', diamond: '◆' };
const sym = symbols[String(args.symbol || 'star').toLowerCase()] || '★';
const max = Math.max(1, Math.round(parseFloat(args.max) || 5));
const value = Math.max(0, Math.min(max, parseFloat(args.value) || 0));
const showValue = String(args.showValue) === 'true';
let szN = parseInt(args.size, 10); const sizeCss = (szN > 0) ? ('font-size:' + Math.min(120, szN) + 'px;') : '';
let gN = parseInt(args.gap, 10); const gap = (gN >= 0 && gN <= 20) ? gN : 1;
let stars = '';
for (let i = 1; i <= max; i++) {
  const fill = Math.max(0, Math.min(1, value - (i - 1))); // 0, .5-ish, or 1
  const pct = Math.round(fill * 100);
  stars += `<span class="mdp-rt-star"><span class="mdp-rt-empty">${sym}</span><span class="mdp-rt-fill" style="width:${pct}%;">${sym}</span></span>`;
}
const num = showValue ? `<span class="mdp-rt-num">${value}${'/' + max}</span>` : '';
const styleVars = `--rt-color:${color}; --rt-gap:${gap}px; ${sizeCss}` + (empty ? `--rt-empty-c:${empty};` : '');
return `<span class="mdp-mod-rating" style="${styleVars}" title="${value} / ${max}">${stars}${num}</span>`;
